sql:
SELECT DISTINCT p.player_name, pa.award_name 
FROM players p 
INNER JOIN player_awards pa ON p.player_id = pa.player_id;

SELECT player_id, COUNT(*) AS total_awards
FROM player_awards
GROUP BY player_id;

external_knowledge:
- The top 5 highest-paid players are determined by their total salary across all contracts; 
- The season just ended is defined as the year of the contract end date, assuming contracts end on December 31st;
- The most spectators refers to the average game attendance in the last season.

sql:
SELECT p.position, AVG(p.height) AS average_height
FROM players p
GROUP BY p.position;

SELECT AVG(c.salary) AS average_salary
FROM contracts c
WHERE c.team_id = 1;
